mapper.select:
select id, commodity_name, commodity_price, commodity_discounted_price, category_id, oversold_configurations, alarm_threshold, description, category, status, available_status,business_suitable as businessSuitable, if(oversold=oversold_configurations,0,1) as hasStock, dest, server_names, (select count(1) from `order` o join order_commodity oc on o.id = oc.order_id where o.is_deleted = 0 and oc.is_deleted = 0 and o.status = 'WAIT_ALLOCATION_RESOURCES' and oc.commodity_id = commodity.id) as oversold, (select count(1) from server_resources where commodity_id = commodity.id and is_deleted = 0 and sales_status = 'NOT_SALE' and resources_status = 'NORMAL' and available_status = 1) as inventory, (select count(1) from server_resources where commodity_id=commodity.id and is_deleted = 0) as resourceNum from commodity
1 = 1 and is_deleted = 0
and commodity_name like concat('%',#{dto.commodityName},'%')
and category_id = #{dto.categoryId}
and oversold_configurations = #{dto.oversoldConfigurations}
and oversold = #{dto.oversold}
and inventory = #{dto.inventory}
and alarm_threshold = #{dto.alarmThreshold}
and `status` = #{dto.status}
and available_status = #{dto.availableStatus}
and inventory > alarm_threshold
and inventory <= alarm_threshold
and inventory = 0
and oversold > 0
order by create_time desc
